text:
중복 제거: DISTINCT

DISTINCT 기본


SELECT 절에서 사용.
결과에서 중복된 행(row)을 제거.
모든 컬럼 조합이 동일하면 한 번만 남음.

proc sql;
   select distinct department
   from employees;
quit;

부서 이름(department)이 중복 없이 한 번씩만 출력.


여러 컬럼과 함께 사용


여러 변수 조합이 동일하면 중복 제거.

proc sql;
   select distinct department, job_title
   from employees;
quit;

(department, job_title) 조합이 같은 경우 한 줄만 출력.


COUNT(DISTINCT …)


특정 변수의 고유값 개수 세기.
SAS PROC SQL은 COUNT(DISTINCT col) 지원.

proc sql;
   select count(distinct department) as Dept_N
   from employees;
quit;

department의 고유 개수 출력.


DISTINCT와 GROUP BY 차이


DISTINCT: 단순히 중복 제거 → 전체 결과를 unique set으로 만듦.
GROUP BY: 그룹별 집계 수행 → 집계함수와 함께 사용.

/* DISTINCT */
proc sql;
   select distinct department
   from employees;
quit;

/* GROUP BY */
proc sql;
   select department, avg(salary) as Avg_Sal
   from employees
   group by department;
quit;

DISTINCT: 그냥 고유 부서 목록, GROUP BY: 부서별 평균 급여

서브쿼리, 인라인 뷰 활용

서브쿼리 (Subquery)


다른 SQL문 안에 포함된 하위 SELECT문. 보통 WHERE, HAVING, SELECT 절에서 많이 사용됨.


단일 값 서브쿼리; 서브쿼리가 하나의 값을 반환.

proc sql;
   select id, name, salary
   from employees
   where salary &gt; (select avg(salary) from employees);
quit;

직원 급여가 전체 평균 급여보다 큰 행만 선택.


다중 값 서브쿼리 (IN, EXISTS, NOT EXISTS); 서브쿼리가 여러 행을 반환.


IN

proc sql;
   select id, name
   from employees
   where department in (select department from departments where region = 'EU');
quit;

유럽(EU) 지역 부서에 속한 직원만 선택.
EXIST

proc sql;
   select *
   from tableA as a
   where exists (
      select 1
      from tableB as b
      where a.id = b.id
   );
quit;

a.id=b.id 조건을 만족하는 행이 tableB에 존재하면 True


상관 서브쿼리 (Correlated Subquery); 서브쿼리가 바깥 쿼리의 컬럼과 연결됨.

proc sql;
   select e1.id, e1.salary
   from employees e1
   where salary &gt; (select avg(e2.salary) 
                   from employees e2
                   where e1.department = e2.department);
quit;

각 부서 평균 급여보다 급여가 높은 직원 선택.


인라인 뷰 (Inline View); FROM 절 안에 들어가는 서브쿼리 (일시적 테이블처럼 사용).

proc sql;
   select department, Avg_Sal
   from (select department, avg(salary) as Avg_Sal
         from employees
         group by department) as dept_avg
   where Avg_Sal &gt; 50000;
quit;

먼저 부서별 평균 급여(dept_avg)를 만든 후, 평균이 50,000 초과인 부서만 선택.

생성: %LET, INTO:, CALL SYMPUTX









방법
사용 위치
생성 범위
용도




%LET
매크로 언어 직접
전역
고정 상수/문자 할당


INTO:
PROC SQL
전역
SQL 결과 → 매크로 변수


CALL SYMPUTX
DATA step
기본 전역 (지역도 가능)
데이터 값 → 매크로 변수




%LET; 전역 매크로 변수를 생성


간단히 상수 값이나 문자열을 할당할 때 사용

%let today = 2025-09-06;
%put &=today;

항상 전역 변수(global)
문자/숫자 상관없이 문자열처럼 저장
공백 포함 시 따옴표 사용 필요 (%let name=“My Name”;)


INTO:; PROC SQL 안에서 결과를 매크로 변수로 저장


단일 값 저장

proc sql noprint;
   select avg(salary)
   into :avg_sal
   from employees;
quit;

%put &=avg_sal;

평균 급여를 &avg_sal 매크로 변수에 저장

만약 AVG_SAL이 5라면,
AVG_SAL=5
이렇게 결과가 나옴.



여러 값 저장

공백 구분:
proc sql noprint;
   select name
   into :namelist separated by ' '
   from employees;
quit;

%put &=namelist;

만약 NAMELIST=Alice Bob Carol라면, Alice Bob Carol 이런 식으로 저장
그래서 결과는 NAMELIST=Alice Bob Carol 이렇게 나옴
여러 개 매크로 변수에 순서대로 할당:

proc sql noprint;
   select name
   into :name1-:name3
   from employees;
quit;

%put &name1 &name2 &name3;

CALL SYMPUTX; DATA step에서 매크로 변수 생성

data _null_;
   set employees;
   call symputx('empname', name);
run;

%put &=empname;

마지막 관측치의 name 값이 &empname에 저장
행 단위 반복 가능 → 관측치별 매크로 변수 만들 수 있음
SYMPUTX는 공백 제거하고, 자동으로 문자/숫자 처리
SYMPUT보다 SYMPUTX를 쓰는 게 권장됨


다음 코드에서 maxage라는 매크로 변수를 생성하시오.

data _null_;
   set sashelp.class end=last;
   retain maxage 0;
   if Age &gt; maxage then maxage=Age;
   if last then call symputx('maxage', maxage);
run;

%put &=maxage;

Scope 제어: %GLOBAL, %LOCAL, SYMPUTX 옵션








방법
생성 범위
특징




%GLOBAL
전역
항상 전역 매크로 변수 생성 (세션 전체에서 유효)


%LOCAL
지역
매크로 안에서만 사용, 매크로 종료 시 삭제


CALL SYMPUTX
기본 전역, 옵션으로 제어
'G' 전역, 'L' 지역 / 기본은 실행 환경 따라 자동 결정




매크로 변수 스코프 개념


전역(Global): SAS 세션 내내 유지, 모든 매크로에서 접근 가능
지역(Local): 특정 매크로 실행 중에만 존재, 매크로 종료 시 자동 삭제


%GLOBAL


전역 매크로 변수를 명시적으로 선언
매크로 외부·내부 어디서든 사용 가능

%global gvar;
%let gvar = 100;
%put &=gvar;   /* 100 */

이미 존재하는 전역 변수면 값은 유지, 없으면 새로 생성


%LOCAL


지역 매크로 변수 선언 (해당 매크로 안에서만 유효)

%macro test;
   %local lvar;
   %let lvar = 200;
   %put &=lvar;
%mend;
%test;
%put &=lvar; 

매크로 종료 시 자동 소멸


CALL SYMPUTX 옵션


DATA step에서 매크로 변수 생성 시 스코프 제어 가능

%macro demo;
   data _null_;
      x = 300;
      call symputx('mvar', x, 'L'); /* Local */
   run;
   %put Local var = &mvar;
%mend;
%demo;

세 번째 인수(스코프 지정):

‘G’ → 전역(Global) 매크로 변수 생성
‘L’ → 지역(Local) 매크로 변수 생성

생략 시:

매크로 실행 중이면 지역(local)
아니면 전역(global)

이름 구분자(.) 활용

기본 예시

%let var = name;

%put &var1;    /* 매크로 변수 var1 찾음 → 정의 안 되어 있으면 경고 */
%put &var.1;   /* 매크로 변수 var 찾고, 뒤에 "1" 붙임 → name1 */

&var1 은 var1이라는 매크로 변수를 찾음.
&var.1 은 var 매크로 변수의 값(name) + 1 = name1


문자열 연결할 때

%let month = Jan;

%put &month.Sales;   /* 매크로 변수 monthSalses 찾으려 함 → 에러 */
%put &month..Sales;   /* month → Jan + Sales → JanSales */

&month.Sales 처럼 구분자 붙여야 원하는 결과 나옴.


루프에서 자주 쓰임

%macro loop;
   %do i=1 %to 3;
      %let var&i = value&i;
      %put &&var&i;    /* && → &var1, &var2 ... */
   %end;
%mend;
%loop;

이때도 &var.&i 혹은 &var&i 로 처리해야 함.
.을 붙이면 매크로 변수명과 루프 인덱스 구분이 확실해짐.

매크로 프로그램

정의/호출: %MACRO … %MEND
%macro 매크로이름(매개변수);
   /* 매크로 코드 */
%mend 매크로이름;

%macro ~ %mend 사이에 매크로 프로그램 코드 작성
호출할 때는 %매크로이름(인수) 형태로 실행


매크로 프로그램 생성과 호출


매개변수 없는 매크로

%macro hello;
   %put Hello, SAS Macro!;
%mend hello;

%hello;

%hello; 실행 시 로그에 Hello, SAS Macro! 출력


매개변수 있는 매크로

%macro greet(name);
   %put Hello, &name!;
%mend greet;

%greet(Name);

%greet(Name); 실행 시 Hello, Name! 출력



파라미터 유무 호출

매개변수의 종류


위치 매개변수(Positional parameter)

%macro report(dept, year);
   %put Department=&dept, Year=&year;
%mend;
%report(HR, 2025);

키워드 매개변수(Keyword parameter); 기본값 지정 가능

%macro report(dept=Sales, year=2025);
   %put Department=&dept, Year=&year;
%mend;
%report();                /* Sales, 2025 */
%report(dept=HR, year=2024); /* HR, 2024 */

조건문과 반복문



조건문: %IF-%THEN-%ELSE

조건문 %IF … %THEN … %ELSE

%macro check(num);
   %if &num &gt; 0 %then %put Positive;
   %else %put Non-positive;
%mend;
%check(10);

minoperator

minoperator는 in을 쓸 수 있게 해줌

%macro avgfuel(loc) / minoperator;
%else %if &loc in ASIA EUROPE %then %do;



반복문: %DO-%END

반복문 %DO ~ %END

%macro loop(n);
   %do i=1 %to &n;
      %put Iteration &i;
   %end;
%mend;
%loop(3);

매크로 프로그램 활용 예시

%macro summary(dataset, var);
   proc sql;
      select mean(&var), max(&var), min(&var)
      from &dataset;
   quit;
%mend;

%summary(sashelp.class, height);

sashelp.class 데이터에서 height 변수의 평균, 최댓값, 최솟값 출력



AUTOCALL facility (재사용 가능한 매크로 저장/호출)
/* AUTOCALL 세팅 */
options mautosource
        sasautos = ("c:\cert\programs" "!sasroot\core\sasmacro");

/* c:\cert\programs\greet.sas 파일 내용:
   %macro greet(name);
      %put Hello, &name!;
   %mend;
*/

/* 호출 */
%greet(Max);

Hello, Max!

디버깅

MLOGIC, MPRINT, SYMBOLGEN









옵션
역할
로그에 출력되는 내용
예시




MLOGIC
매크로 실행 흐름 표시
매크로 시작/끝, %IF 조건 평가
%if가 TRUE/FALSE로 나오는지 확인


MPRINT
매크로가 생성한 SAS 코드 표시
실제 실행된 DATA/PROC 구문
확장된 코드 확인


SYMBOLGEN
매크로 변수 치환 과정 표시
&var → 값
매크로 변수 값 확인




MLOGIC


매크로 실행 시, 매크로의 논리 흐름(logic)을 로그에 출력
어떤 매크로가 호출됐는지, %IF 조건이 어떻게 평가됐는지 보여줌

options mlogic;

%macro test(x);
   %if &x &gt; 10 %then %put Greater than 10;
   %else %put 10 or less;
%mend;

%test(5);

log

MLOGIC(TEST):  Beginning execution.
MLOGIC(TEST):  %IF condition &x &gt; 10 is FALSE
MLOGIC(TEST):  Ending execution.

MPRINT


매크로 실행 시, 실제로 실행된 SAS 코드를 로그에 출력
매크로가 어떤 DATA/PROC 구문으로 확장(expand)되는지 확인 가능

options mprint;

%macro step;
   proc print data=sashelp.class(obs=5);
   run;
%mend;

%step;

log

MPRINT(STEP):   proc print data=sashelp.class(obs=5);
MPRINT(STEP):   run;

SYMBOLGEN


매크로 변수 치환 과정을 로그에 출력
어떤 값으로 변환되는지 확인 가능

options symbolgen;

%let name = Name;
%put Hello, &name;

log

SYMBOLGEN:  Macro variable NAME resolves to Name


%PUT 로그 확인

매크로 코드에서 메시지를 SAS 로그에 출력
주로 디버깅, 매크로 변수 값 확인에 사용










사용법
설명
예시
결과




%put &var;
매크로 변수 값 출력
%put &city;
London


%put &=var;
변수명=값 출력
%put &=city;
CITY=London


%put NOTE: 등
로그 메시지 레벨 지정
%put NOTE: Hello;
NOTE: Hello


%put _all_;
모든 매크로 변수 표시
%put _all_;
전역/자동 변수 목록



%let name = Name;
%put Hello, &name;

log

Hello, Name

매크로 변수 값 확인

%let city = London;
%put &=city;

log

CITY=London

&=변수명 형태로 쓰면 변수명=값 형태로 깔끔하게 출력됨


사용자 정의 메시지

%put NOTE: Macro started!;
%put WARNING: Check input dataset;
%put ERROR: Something went wrong;

log

NOTE: Macro started!
WARNING: Check input dataset
ERROR: Something went wrong

실제 SAS 로그의 NOTE / WARNING / ERROR 스타일로 표시됨


시스템 매크로 변수 출력

%put _automatic_;   /* 자동 생성된 매크로 변수 */
%put _user_;        /* 사용자가 만든 매크로 변수 */
%put _all_;         /* 모든 매크로 변수 */
GLOBAL CITY London
AUTOMATIC SYSDATE9 06SEP2025

%put

% put error:쓰고 log에 print 안 되게 하는 법

%let a=0;

%macro test;
   %if &a %then %put ERROR: Something wrong.;
%mend;
%test;

a가 0이면 에러 log안 나오게
USER 키워드는 사용자가 만든 모든 매크로 변수 + global + local를 로그에 보여줌

%let global1=AAA;

%macro demo;
   %let local1=BBB;
   %global global2;
   %let global2=CCC;

   %put ---- Inside macro ----;
   %put _USER_;
%mend;

%demo

%put ---- After macro ----;
%put _USER_;

log 결과

GLOBAL GLOBAL1 AAA
GLOBAL GLOBAL2 CCC
LOCAL  LOCAL1 BBB

---- After macro ----
GLOBAL GLOBAL1 AAA
GLOBAL GLOBAL2 CCC

%put _ALL_; → 자동변수 + 사용자 변수 + 시스템 변수 전부 다
%put _AUTOMATIC_; → 자동으로 제공되는 시스템 매크로 변수만
%put _GLOBAL_; → 글로벌 변수만
%put _LOCAL_; → 매크로 실행 중일 때만 로컬 변수만

proc sql noprint;
    select name
    into :namelist separated by ','
    into :n1 - :n5
    into :avg_h, :avg_w
    from sashelp.class
    where sex='F';
quit;

디버깅 활용


보통 MLOGIC, MPRINT, SYMBOLGEN 옵션과 같이 %PUT을 넣어 매크로 변수 값이 제대로 넘어오는지 확인

%macro demo(x);
   %put NOTE: Parameter X = &x;
%mend;

%demo(100);

log

NOTE: Parameter X = 100


put vs putlog

put

%LET → 매크로 변수 name 생성 (Name)
%PUT → 매크로 실행 시점에 로그에 문자열 출력
결과 (로그):


%let name=Mike;
%put Hello, &name.;
결과: Hello, Mike

put log

DATA step 실행 중, putlog 문이 SAS 로그에 메시지 기록
“현재 값은” → 문자열 그대로 출력
x= y= → 변수 이름과 값 함께 출력
결과 (로그):


data _null_;
   x = 10;
   y = 20;
   putlog "현재 값은 " x= y=;
run;
결과: 현재 값은 x=10 y=20

데이터 기반 매크로

간접참조&&

매크로 변수 이름을 다른 매크로 변수 값으로부터 동적으로 만들어서 참조하는 것.
&& 조합은 치환 과정에서 단계적으로 풀리면서 최종 매크로 변수로 변환됨.
아래와 같은 매크로 변수들이 있을 때, var1=Height, var2=Weight, var3=Age. 루프를 이용해 차례대로 변수명을 출력하시오.

&&var&i → &var1 → Height, 두 번 풀려서 최종적으로 변수명이 나옴


%let var1=Height;
%let var2=Weight;
%let var3=Age;

%macro show;
   %do i=1 %to 3;
      %put &&var&i;
   %end;
%mend;

%show

Dictionary table 기반 매크로

반복적 매크로 호출 생성

간단한 반복문으로 매크로 호출

%macro call_loop;
   %do i=1 %to 3;
      %put This is loop number &i;
   %end;
%mend;

%call_loop;

log

This is loop number 1
This is loop number 2
This is loop number 3

매크로 변수 리스트 기반 반복 호출

%let city1=Seoul;
%let city2=London;
%let city3=Paris;

%macro city_loop;
   %do i=1 %to 3;
